// Error Catcher — Master v2
// Captures ALL workflow failures, formats alert, routes to multiple channels

const err = $input.first().json;
const timestamp = new Date().toISOString();
const workflowName = err.workflow?.name || 'Unknown Workflow';
const nodeName = err.node || 'Unknown Node';
const errorMsg = err.error?.message || err.message || 'No message';
const executionId = err.execution?.id || 'N/A';
const startedAt = err.execution?.startedAt || timestamp;

// Determine severity
let severity = '⚠️ MEDIUM';
if (workflowName.includes('Utopia') || workflowName.includes('Deli') || workflowName.includes('Checkout')) {
  severity = '🚨 CRITICAL — CLIENT REVENUE IMPACT';
} else if (workflowName.includes('Lead') || workflowName.includes('Scraper')) {
  severity = '🔶 HIGH — LEAD GENERATION IMPACT';
}

const payload = {
  subject: `${severity}: n8n Error — ${workflowName}`,
  text: `${severity}

📋 Workflow: ${workflowName}
🔧 Failed Node: ${nodeName}
❌ Error: ${errorMsg}
⏰ Time: ${startedAt}
🔗 Execution ID: ${executionId}
🆔 Severity: ${severity}

Full error payload:
${JSON.stringify(err, null, 2)}

---
Auto-generated by Error Catcher — Master v2
${timestamp}`,
  severity: severity,
  workflowName: workflowName,
  nodeName: nodeName,
  errorMsg: errorMsg,
  executionId: executionId,
  timestamp: timestamp
};

return [{ json: payload }];

// Log error to SQLite for audit trail
const error = $input.first().json;

// This will be connected to a SQLite/Postgres node in production
// For now, returns structured log entry

const logEntry = {
  id: error.executionId || 'manual-' + Date.now(),
  workflow_name: error.workflowName,
  node_name: error.nodeName,
  error_message: error.errorMsg,
  severity: error.severity,
  timestamp: error.timestamp,
  resolved: false,
  resolved_at: null,
  resolved_by: null
};

return [{ json: logEntry }];
